(function(){
  function bankQ(arr, tag, color, bg){ const e = pick(arr); return mkQ(e.q, e.a, shuffle([...e.o]), e.h, tag, color, bg); }
  OKR_TH.weather = `<h3>Погода и климат</h3><div class="fm"><b>Погода</b> — какая сейчас температура, облачность, ветер, осадки.<br><b>Климат</b> — какая погода бывает в этой местности много лет подряд.<br>Термометр измеряет температуру, флюгер показывает направление ветра.</div><p>Зимой холоднее, летом теплее. Осадки бывают в виде дождя, снега и града.</p>`;
  OKR_TH.map = `<h3>Карта и стороны света</h3><div class="fm">Север — сверху на карте<br>Юг — снизу<br>Запад — слева<br>Восток — справа</div><p>Компас помогает определить стороны света. Солнце встаёт на востоке, а садится на западе.</p>`;
  function genWeather3(){
    return bankQ([
      {q:'Что показывает термометр?', a:'температуру', o:['температуру','скорость ветра','влажность почвы','время'], h:'Термометр нужен для температуры воздуха и воды.'},
      {q:'Дождь, снег и град — это:', a:'осадки', o:['осадки','ветер','облачность','туман'], h:'То, что падает из облаков.'},
      {q:'Сильное движение воздуха — это:', a:'ветер', o:['ветер','туман','мороз','климат'], h:'Ветер бывает слабым и сильным.'},
      {q:'Погода зимой чаще всего:', a:'холоднее, чем летом', o:['холоднее, чем летом','такая же, как летом','всегда жаркая','без осадков'], h:'Зимой температура обычно ниже.'},
      {q:'Климат — это:', a:'погода, которая повторяется много лет', o:['погода, которая повторяется много лет','погода только на один день','только ветер','только температура'], h:'Климат изучают долгое время.'},
      {q:'Что бывает после сильного дождя и солнца?', a:'радуга', o:['радуга','снегопад','метель','ледоход'], h:'Разноцветная дуга на небе.'},
      {q:'Туман — это когда:', a:'воздух наполнен мельчайшими каплями воды', o:['воздух наполнен мельчайшими каплями воды','идёт сильный снег','дует ветер','гремит гром'], h:'Из-за тумана далеко не видно.'},
      {q:'Какой прибор помогает узнать погоду на улице?', a:'термометр', o:['термометр','линейка','компас','глобус'], h:'Им измеряют температуру.'}
    ], 'Погода и климат', '#2563eb', '#dbeafe');
  }
  function genMap3(){
    return bankQ([
      {q:'На компасе буква N означает:', a:'север', o:['север','юг','восток','запад'], h:'N = North, по-русски север.'},
      {q:'Солнце утром появляется на:', a:'востоке', o:['востоке','западе','севере','юге'], h:'Встаёт на востоке, садится на западе.'},
      {q:'На обычной карте север находится:', a:'сверху', o:['сверху','снизу','слева','справа'], h:'Так принято на большинстве карт.'},
      {q:'Если ты повернулся лицом на север, то восток будет:', a:'справа', o:['справа','слева','сзади','внизу'], h:'Север впереди — восток справа.'},
      {q:'Если идти к закату, ты идёшь на:', a:'запад', o:['запад','восток','север','юг'], h:'Закат бывает на западе.'},
      {q:'Как называется уменьшенное изображение Земли на плоскости?', a:'карта', o:['карта','компас','глобус','атлас'], h:'Плоское изображение местности.'},
      {q:'Глобус — это модель:', a:'Земли', o:['Земли','Солнца','Луны','России'], h:'Шар, похожий на нашу планету.'},
      {q:'Если стрелка компаса указывает вверх на карте, это направление:', a:'север', o:['север','юг','запад','восток'], h:'Север на карте обычно сверху.'}
    ], 'Карта и стороны света', '#0d9488', '#ccfbf1');
  }
  const okr = SUBJ.find(s => s.id === 'okr');
  if(okr){
    if(!okr.tops.find(t => t.id === 'weather')) okr.tops.push({id:'weather', nm:'Погода и климат', gen:genWeather3, th:OKR_TH.weather, dot:'#2563eb'});
    if(!okr.tops.find(t => t.id === 'map')) okr.tops.push({id:'map', nm:'Карта и стороны света', gen:genMap3, th:OKR_TH.map, dot:'#0d9488'});
  }
})();


